SELECT 
    c.*,
    ch.channel_name as channel_name
FROM tb_company c
LEFT JOIN tb_company_channel_map m ON c.company_id = m.company_id AND m.status = 'ACTIVE'
LEFT JOIN tb_channel ch ON m.channel_id = ch.channel_id


        AND c.tenant_id = #{tenantId}


        AND c.company_type = #{companyType}


        AND c.status = #{status}


        AND (c.company_name LIKE CONCAT('%', #{searchKeyword}, '%')
          OR c.business_no  LIKE CONCAT('%', #{searchKeyword}, '%'))


ORDER BY c.created_at DESC
LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

